import json
from datetime import datetime

def extract_cloudwatch_log_info(event):
    """
    Extracts log message and timestamp from AWS CloudWatch log event.

    Args:
        event: AWS CloudWatch log event (dict or JSON string)

    Returns:
        Dictionary with 'message' and 'timestamp' keys
    """
    if isinstance(event, str):
        event = json.loads(event)

    result = {
        'message': event.get('message', ''),
        'timestamp': event.get('timestamp')
    }

    if result['timestamp']:
        try:
            result['timestamp'] = datetime.fromtimestamp(result['timestamp'] / 1000).isoformat()
        except (ValueError, TypeError):
            pass

    return result


# Example usage with typical CloudWatch log event structure
if __name__ == "__main__":
    sample_event = {
        'messageType': 'DATA_MESSAGE',
        'owner': '123456789012',
        'logGroup': '/aws/lambda/my-function',
        'logStream': '2023/10/15/[$LATEST]abcdef1234567890',
        'subscriptionFilters': ['LambdaStream'],
        'logEvents': [
            {
                'id': '35683658089214582180394806857361982823',
                'message': 'START RequestId: 1234567890 Version: $LATEST',
                'timestamp': 1697361600000
            }
        ]
    }

    # Extract from logEvents array
    log_event = sample_event['logEvents'][0]
    result = extract_cloudwatch_log_info(log_event)
    print(result)
